fn delay_for(attempt: u32, opts: &RetryOptions) -> Duration {
    let mut d = opts.initial_delay.as_secs_f64();
    for _ in 0..attempt {
        d *= opts.backoff_multiplier;
    }
    let max = opts.max_delay.as_secs_f64();
    Duration::from_secs_f64(d.min(max))
}

